qry:select.qry:xquery:
					for $r in sql('
			SELECT 
			EVA02_EVALUACION.oi_evaluacion, EVA02_EVALUACION.c_resultado,
			EVA02_EVALUACION.oi_personal_emp, EVA02_EVALUACION.oi_evento, 
			EVA02_EVALUACION.oi_evaluador, EVA01_EVENTOS.c_evento,
			PER02_PERSONAL_EMP.e_numero_legajo, PER01_PERSONAL.d_ape_y_nom,
			EVA02_EVALUACION.f_evaluacion, EVA02_EVALUACION.c_estado
			FROM 
			EVA02_EVALUACION, EVA01_EVENTOS, PER02_PERSONAL_EMP, PER01_PERSONAL
			JOIN
			EVA02_EVALUACION.oi_evento INNER EVA01_EVENTOS.oi_evento,
			EVA02_EVALUACION.oi_personal_emp INNER PER02_PERSONAL_EMP.oi_personal_emp,
			PER02_PERSONAL_EMP.oi_personal INNER PER01_PERSONAL.oi_personal
      WHERE
      EVA02_EVALUACION.oi_evento = {#SOURCE:@oi_evento}
			{%? (#SOURCE:@mis_evaluados='1')	{% AND EVA02_EVALUACION.oi_evaluador = {#SOURCE:@oi_personal_emp_user} %} 
      		{% 
      			{%? (#SOURCE:@oi_evaluador!='')	{% AND EVA02_EVALUACION.oi_evaluador = {#SOURCE:@oi_evaluador} %} {% %} %}
      		%} %}     
      {%? (#SOURCE:@oi_supervisor!='')	{% AND EVA02_EVALUACION.oi_supervisor = {#SOURCE:@oi_supervisor} %} {% %} %}
      {%? (#SOURCE:@c_estado!='')	{% AND EVA02_EVALUACION.c_estado= {#SOURCE:@c_estado} %} {% %} %}
      {%? (string(#SOURCE:ROWS/ROW/@id)!='') {% AND EVA02_EVALUACION.oi_personal_emp  in ({%=string(#SOURCE:ROWS/ROW/@id) %}) %} {%  %} %}
      ORDER BY
      {%? (#SOURCE:@ATRIB_ORDEN1!='')	{% {%=#SOURCE:@ATRIB_ORDEN1%} {%? (#SOURCE:@ORDEN1!='') {% {%=#SOURCE:@ORDEN1%}, %} {% ASC, %}	%} %} {% %} %}
			oi_evaluacion	ASC
	    ')/ROWS/ROW

					for $r in sql('
			SELECT
			EVA02_EVALUACION.oi_evaluacion, EVA02_EVALUACION.f_evaluacion, 
			EVA01_EVENTOS.c_evento, PER02_PERSONAL_EMP.e_numero_legajo, PER02_PERSONAL_EMP.oi_personal_emp,
			PER01_PERSONAL.d_ape_y_nom, EVA02_EVALUACION.c_estado
			FROM
			EVA02_EVALUACION, EVA01_EVENTOS, PER02_PERSONAL_EMP, PER01_PERSONAL
			JOIN
			EVA02_EVALUACION.oi_evento INNER EVA01_EVENTOS.oi_evento,
			EVA02_EVALUACION.oi_personal_emp INNER PER02_PERSONAL_EMP.oi_personal_emp,
			PER02_PERSONAL_EMP.oi_personal INNER PER01_PERSONAL.oi_personal
			WHERE
			EVA02_EVALUACION.oi_evento = {#SOURCE:@oi_evento}
      {%? (#SOURCE:@mis_evaluados='1')	{% AND EVA02_EVALUACION.oi_evaluador = {#SOURCE:@oi_personal_emp_user} %} 
      		{% 
      			{%? (#SOURCE:@oi_evaluador!='')	{% AND EVA02_EVALUACION.oi_evaluador = {#SOURCE:@oi_evaluador} %} {% %} %}
      		%} %}      
      {%? (#SOURCE:@oi_supervisor!='')	{% AND EVA02_EVALUACION.oi_supervisor = {#SOURCE:@oi_supervisor} %} {% %} %}
      {%? (#SOURCE:@c_estado!='')	{% AND EVA02_EVALUACION.c_estado= {#SOURCE:@c_estado} %} {% %} %}
      {%? (string(#SOURCE:ROWS/ROW/@id)!='') {% AND EVA02_EVALUACION.oi_personal_emp  in ({%=string(#SOURCE:ROWS/ROW/@id) %}) %} {%  %} %}
      ORDER BY
      {%? (#SOURCE:@ATRIB_ORDEN1!='')	{% {%=#SOURCE:@ATRIB_ORDEN1%} {%? (#SOURCE:@ORDEN1!='') {% {%=#SOURCE:@ORDEN1%}, %} {% ASC, %}	%} %} {% %} %}
    	oi_evaluacion	ASC
      ')/ROWS/ROW
